"use client";
import { useEffect, useState, useCallback } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { Loader2, Monitor, Smartphone, ShieldCheck, RefreshCw, ArrowLeft, Laptop, HardDrive } from 'lucide-react';
import DeviceModal from '@/components/DeviceModal';

export default function ScanDetailPage() {
    const { id } = useParams();
    const router = useRouter();
    const [scan, setScan] = useState<any>(null);
    const [devices, setDevices] = useState([]);
    const [selectedDevice, setSelectedDevice] = useState<any>(null);
    const [devicePorts, setDevicePorts] = useState([]);
    const [isRefreshing, setIsRefreshing] = useState(false);

    const fetchData = useCallback(async () => {
        if (!id) return;
        setIsRefreshing(true);
        try {
            const resScan = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/scans/${id}`);
            const dataScan = await resScan.json();
            setScan(dataScan);

            const resDevs = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/devices/?scan_id=${id}`);
            const dataDevs = await resDevs.json();
            setDevices(dataDevs);
        } catch (err) {
            console.error("Fetch error:", err);
        } finally {
            setIsRefreshing(false);
        }
    }, [id]);

    useEffect(() => {
        fetchData();
        const timer = setInterval(fetchData, 5000);
        return () => clearInterval(timer);
    }, [fetchData]);

    const handleDeviceClick = async (device: any) => {
        setSelectedDevice(device);
        try {
            const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/devices/${device.id}/ports`);
            const ports = await res.json();
            setDevicePorts(ports);
        } catch (err) {
            console.error("Ports fetch error:", err);
            setDevicePorts([]);
        }
    };

    const getIcon = (guess: string) => {
        const text = guess?.toLowerCase() || "";
        if (text.includes('phone') || text.includes('android') || text.includes('ios')) return <Smartphone />;
        if (text.includes('laptop') || text.includes('pc') || text.includes('windows')) return <Laptop />;
        return <Monitor />;
    };

    if (!scan) return <div className="p-20 text-center"><Loader2 className="animate-spin inline mr-2" /> Loading...</div>;

    return (
        <div className="min-h-screen bg-slate-50 p-4 md:p-8">
            <div className="max-w-6xl mx-auto">
                <div className="flex justify-between items-center mb-10">
                    <button onClick={() => router.push('/scans')} className="flex items-center text-slate-500 hover:text-blue-600 font-bold transition-colors">
                        <ArrowLeft className="w-5 h-5 mr-2" /> Back to History
                    </button>
                    <div className="flex items-center gap-4 bg-white p-4 rounded-2xl shadow-sm border border-slate-200">
                        <div className="text-right">
                            <h1 className="text-xl font-black text-slate-900 leading-none">{scan.ssid}</h1>
                            <p className="text-[10px] text-slate-400 font-bold uppercase mt-1 tracking-tighter">Network Snapshot</p>
                        </div>
                        <button onClick={fetchData} className="p-2 bg-slate-50 rounded-xl hover:bg-blue-50 transition-colors">
                            <RefreshCw className={`w-5 h-5 text-blue-600 ${isRefreshing ? 'animate-spin' : ''}`} />
                        </button>
                    </div>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                    {devices.map((dev: any, idx) => (
                        <div
                            key={dev.id || idx}
                            onClick={() => handleDeviceClick(dev)}
                            className="bg-white p-6 rounded-3xl shadow-sm border-2 border-transparent hover:border-blue-500 transition-all cursor-pointer group hover:shadow-xl"
                        >
                            <div className="flex justify-between items-start mb-6">
                                <div className="bg-slate-100 p-4 rounded-2xl text-slate-600 group-hover:bg-blue-600 group-hover:text-white transition-all">
                                    {getIcon(dev.device_guess)}
                                </div>
                                <div className="flex flex-col items-end">
                                    <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-2 py-1 rounded-md uppercase mb-1">
                                        {dev.state}
                                    </span>
                                    <span className="text-[10px] font-bold text-slate-300 uppercase">IP4 Address</span>
                                </div>
                            </div>

                            <h3 className="font-bold text-slate-900 text-lg mb-1 leading-tight">
                                {dev.device_guess || "Unknown Device"}
                            </h3>

                            <p className="text-blue-600 font-mono font-bold text-sm">
                                {dev.ip4}
                            </p>

                            <p className="text-[10px] text-slate-400 font-mono mt-4 border-t pt-4">
                                MAC: {dev.mac}
                            </p>
                        </div>
                    ))}
                </div>
            </div>

            <DeviceModal
                device={selectedDevice}
                ports={devicePorts}
                onClose={() => setSelectedDevice(null)}
            />
        </div>
    );
}