"use client";
import { X, Cpu, Globe, Shield, Activity } from 'lucide-react';

export default function DeviceModal({ device, onClose, ports }: any) {
    if (!device) return null;

    return (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
            <div className="bg-white rounded-3xl w-full max-w-lg overflow-hidden shadow-2xl animate-in zoom-in duration-200">
                <div className="p-6 border-b flex justify-between items-center bg-slate-900 text-white">
                    <div>
                        <h2 className="text-xl font-bold">Device Inspection</h2>
                        <p className="text-slate-400 text-xs font-mono">{device.mac}</p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors"><X /></button>
                </div>

                <div className="p-8">
                    <div className="flex items-center gap-6 mb-8">
                        <div className="text-5xl p-5 bg-slate-100 rounded-2xl">
                            {/* Using device_guess to determine icon */}
                            {device.device_guess?.toLowerCase().includes('phone') ? '📱' : '💻'}
                        </div>
                        <div>
                            <h3 className="text-2xl font-bold text-slate-800">{device.device_guess || "Unknown Device"}</h3>
                            <p className="text-blue-600 font-mono font-bold">{device.ip4}</p>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4 mb-8">
                        <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                            <span className="text-[10px] uppercase font-bold text-slate-400 block mb-1">OS Name</span>
                            <span className="text-sm font-semibold text-slate-700">{device.os_name || "N/A"}</span>
                        </div>
                        <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                            <span className="text-[10px] uppercase font-bold text-slate-400 block mb-1">Vendor</span>
                            <span className="text-sm font-semibold text-slate-700">{device.vendor || "N/A"}</span>
                        </div>
                        <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                            <span className="text-[10px] uppercase font-bold text-slate-400 block mb-1">OS Accuracy</span>
                            <span className="text-sm font-semibold text-slate-700">{device.os_accuracy}%</span>
                        </div>
                        <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                            <span className="text-[10px] uppercase font-bold text-slate-400 block mb-1">State</span>
                            <span className="text-sm font-semibold text-green-600 capitalize">{device.state}</span>
                        </div>
                    </div>

                    <h4 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
                        <Shield className="w-4 h-4 text-blue-500" /> Open Ports ({ports.length})
                    </h4>
                    <div className="flex flex-wrap gap-2 max-h-40 overflow-y-auto pr-2">
                        {ports.length > 0 ? ports.map((p: any) => (
                            <div key={p.id} className="bg-blue-50 border border-blue-100 px-3 py-2 rounded-lg flex flex-col min-w-[100px]">
                                <span className="text-blue-700 font-bold text-sm">{p.number}/{p.protocol}</span>
                                <span className="text-blue-500 text-[10px] uppercase font-medium">{p.service_name}</span>
                            </div>
                        )) : (
                            <p className="text-slate-400 italic text-sm">No active services detected.</p>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}